#include <stdio.h>
#include <string.h>
#define NV 50257
#define NM 50000
#define T 1024
unsigned char ut[256][3];int ul[256];
char mr[NM][128];int ml[NM];
char tk[NV][64];int tl[NV];
int L(char*s){int n=0;while(s[n])n++;return n;}
void ins(char*s,int n,int id){if(n>63)n=63;memcpy(tk[id],s,n);tl[id]=n;}
int find(char*s,int n,int max){for(int i=0;i<max;i++)if(tl[i]==n&&!memcmp(tk[i],s,n))return i;return -1;}
void uni(){int k=0;for(int i=0;i<256;i++){if(i==32){ut[i][0]=0xC4;ut[i][1]=0xA0;ul[i]=2;continue;}if((i>=33&&i<=126)||(i>=161&&i<=172)||(i>=174&&i<=255)){ut[i][0]=i;ul[i]=1;continue;}int c=256+k;if(i>160)k+=14;if(i==173)k--;ut[i][0]=0xC0|(c>>6);ut[i][1]=0x80|(c&63);ul[i]=2;k++;}}
void load_bpe(char*p){FILE*f=fopen(p,"rb");char ln[256];fgets(ln,256,f);for(int i=0;i<NM;i++){if(!fgets(ln,256,f))break;int n=L(ln);if(n&&ln[n-1]=='\n')n--;ln[n]=0;memcpy(mr[i],ln,n);ml[i]=n;}fclose(f);}
void build_vocab(){for(int i=0;i<256;i++)ins((char*)ut[i],ul[i],i);char g[3]={0xC4,0xA0,0};ins(g,2,256);int id=257;for(int i=0;i<NM&&id<50256;i++){char*p=mr[i],*q=strchr(p,' ');int n=ml[i];if(!q)continue;int la=q-p,lb=n-(q-p)-1;if(la<=0||lb<=0||la>=64||lb>=64)continue;int ai=find(p,la,id),bi=find(q+1,lb,id);if(ai<0||bi<0)continue;char s[128];memcpy(s,tk[ai],tl[ai]);memcpy(s+tl[ai],tk[bi],tl[bi]);ins(s,tl[ai]+tl[bi],id);id++;}while(id<50256){tk[id][0]='?';tl[id++]=1;}tk[50256][0]=0;tl[50256]=0;}
int rank(char*s,int n){for(int i=0;i<NM;i++)if(ml[i]==n&&!memcmp(mr[i],s,n))return i;return -1;}
void enc(char*s,int n,int*ids,int*cnt){
 char p[T][64];int pl[T],c=0;
 for(int i=0;i<n;i++){memcpy(p[c],ut[(unsigned char)s[i]],ul[(unsigned char)s[i]]);pl[c++]=ul[(unsigned char)s[i]];}
 while(c>1){int bi=-1,br=1<<30;for(int i=0;i<c-1;i++){char mp[128];memcpy(mp,p[i],pl[i]);mp[pl[i]]=32;memcpy(mp+pl[i]+1,p[i+1],pl[i+1]);int r=rank(mp,pl[i]+1+pl[i+1]);if(r>=0&&r<br){br=r;bi=i;}}if(bi<0)break;memcpy(p[bi]+pl[bi],p[bi+1],pl[bi+1]);pl[bi]+=pl[bi+1];for(int i=bi+1;i<c-1;i++){memcpy(p[i],p[i+1],64);pl[i]=pl[i+1];}c--;}
 *cnt=c;for(int i=0;i<c;i++){int id=find(p[i],pl[i],NV);ids[i]=id<0?0:id;}
}
int main(int c,char**v){
 uni();load_bpe(v[1]);build_vocab();
 char*tests[]={"The"," answer"," is","The answer is","hello","discuss"," a"};
 int n;int ids[64];
 for(int t=0;t<7;t++){enc(tests[t],L(tests[t]),ids,&n);printf("%s -> %d tokens:",tests[t],n);for(int i=0;i<n;i++)printf(" %d",ids[i]);printf("\n");}
 return 0;
}
EOF
